INSERT INTO `v1_b4901c13aaa63d19af408133ed6f872bc25ae267b0934c9688da9c21eee87ad0` VALUES (103611, 1, 1009813045, 0, "だって今日は私が先生だもん。\n先生らしくしなくっちゃ！", 10, 0, 1009813, 1, 11, 0);
