INSERT INTO `v1_b4901c13aaa63d19af408133ed6f872bc25ae267b0934c9688da9c21eee87ad0` VALUES (102011, 1, 1009813050, 0, "キョウカちゃん、\n張りきってたもんね♪\nどんなお勉強をしたの？", 10, 0, 1009813, 1, 11, 0);
